WITH base AS ( SELECT oph.*, SPLIT_PART(oph.trunk_name, '--', 1) AS from_node, SPLIT_PART(oph.trunk_name, '--', 2) AS to_node FROM mba.tb_roadm_optical_performance_hist oph WHERE oph.ocrtime > RCA.FC_GET_MINUS_DAY(1) AND oph.trunk_name = #{TRUNK_NAME} AND oph.direction = #{DIRECTION}
AND oph.ocrtime <= #{TIME_STAMP}::TIMESTAMP
), max_hist AS ( SELECT trunk_name, direction, sysname, MAX(ocrtime) AS ocrtime FROM base
GROUP BY trunk_name, direction, sysname ), snap AS ( SELECT b.* FROM base b JOIN max_hist m ON b.trunk_name = m.trunk_name AND b.direction = m.direction AND b.sysname = m.sysname AND b.ocrtime = m.ocrtime ), latest_daily AS ( SELECT d.*, ROW_NUMBER() OVER (PARTITION BY d.trunk_name, d.direction, d.sysname ORDER BY d.collection_date DESC) AS rn FROM mba.tb_roadm_optical_performance_daily d WHERE d.trunk_name = #{TRUNK_NAME} AND d.direction = #{DIRECTION} AND d.in_out = 'IN' ) SELECT TO_CHAR(MAX(s.ocrtime), 'YYYY-MM-DD HH24:MI:SS') AS OCRTIME, s.trunk_name, s.direction, s.sysname, COALESCE(MAX(s.routenum), 0) AS routenum, CONCAT( ROUND(MAX(CASE WHEN s.in_out = 'IN' THEN s.value_max END), 1), '/', ROUND(MAX(CASE WHEN s.in_out = 'OUT' THEN s.value_max END), 1) ) AS RX_TX, CONCAT( ROUND(MAX(ld.span_loss)::numeric, 1), '/', ROUND(MAX(ld.node_gain)::numeric, 1) ) AS SPAN_GAIN, COALESCE(ROUND(MAX(ld.node_total_deviation)::numeric, 1), 0) AS NODE_TOTAL_DEVIATION FROM snap s LEFT JOIN mba.tb_roadm_trunk_topology rt ON rt.trunk_name = s.trunk_name LEFT JOIN latest_daily ld ON ld.trunk_name = s.trunk_name AND ld.direction = s.direction AND ld.sysname = s.sysname AND ld.rn = 1 GROUP BY s.trunk_name, s.direction, s.sysname ORDER BY COALESCE(MAX(s.routenum), MAX(rt.routenum), 999999)

