WITH UPSERT AS ( UPDATE mba.tb_roadm_predictive_handling


    HANDLING_TIME = #{handling_time}::TIMESTAMP


    , HANDLING_USER = #{handling_user}


    ,  HANDLING_DEPT = #{handling_dept}


    ,  HANDLING_AGENCY = #{handling_agency}


    , HANDLING_CONTENT = #{handling_content}


WHERE SEQNUM = #{seqnum} RETURNING * )
INSERT INTO
mba.tb_roadm_predictive_handling (
    TICKETNO
    , ISSUE_DATE
    , INSERT_TIME
    , DELETE_YN

    , HANDLING_TIME


    , HANDLING_USER


    , HANDLING_DEPT


    , HANDLING_AGENCY


    , HANDLING_CONTENT

    )
        SELECT
    #{ticketno}::VARCHAR
    , #{issue_date}::DATE
    , now()
    , 'N'

        , #{handling_time}::TIMESTAMP


        , #{handling_user}


        , #{handling_dept}


        , #{handling_agency}


        , #{handling_content}

        WHERE NOT EXISTS(SELECT 1 FROM UPSERT)

INSERT INTO MBA.TB_MBA_TICKET_HANDLING (
    TICKET_ID
    , TICKET_TYPE
    , STATUS
    , RCA_ACCURACY
    , HANDLING_CONTENT

    , HANDLING_USER
    , HANDLING_DEPT
    , HANDLING_AGENCY
    , HANDLING_TIME


    , HANDLING_FIN_USER
    , HANDLING_FIN_DEPT
    , HANDLING_FIN_AGENCY
    , HANDLING_ACK_TIME
    , HANDLING_FIN_CONTENT

    , INSERT_TIME
    , UPDATE_TIME
)
VALUES (
    #{TICKET_ID}
    , #{TICKET_TYPE}
    , #{STATUS}
    , #{RCA_ACCURACY}
    , #{HANDLING_CONTENT}

    , #{HANDLING_USER}
    , #{HANDLING_DEPT}
    , #{HANDLING_AGENCY}
    , NOW()


    , #{HANDLING_FIN_USER}
    , #{HANDLING_FIN_DEPT}
    , #{HANDLING_FIN_AGENCY}
    , NOW()
    , #{HANDLING_FIN_CONTENT}

    , NOW()
    , NOW()
)
ON CONFLICT (TICKET_ID) DO UPDATE SET
    STATUS = #{STATUS}
    , RCA_ACCURACY = #{RCA_ACCURACY}
    , UPDATE_TIME = NOW()

    , HANDLING_USER = #{HANDLING_USER}
    , HANDLING_DEPT = #{HANDLING_DEPT}
    , HANDLING_AGENCY = #{HANDLING_AGENCY}
    , HANDLING_TIME = NOW()
    , HANDLING_CONTENT = #{HANDLING_CONTENT}


    , HANDLING_FIN_USER = #{HANDLING_FIN_USER}
    , HANDLING_FIN_DEPT = #{HANDLING_FIN_DEPT}
    , HANDLING_FIN_AGENCY = #{HANDLING_FIN_AGENCY}
    , HANDLING_ACK_TIME = NOW()
    , HANDLING_FIN_CONTENT = #{HANDLING_FIN_CONTENT}

;
UPDATE MBA.TB_MBA_TICKET_CURRENT
SET STATUS = #{STATUS}
WHERE TICKET_ID = #{TICKET_ID}
;
